export const ROUTES = APP_CONTENT.routes;
export const LEVEL_TIERS = APP_CONTENT.progression.levelTiers;
export const LEVEL_TITLES = APP_CONTENT.progression.levelTitles;
export const QUESTS = APP_CONTENT.quests.items;
export const BADGES = APP_CONTENT.badges;
export const LESSONS = APP_CONTENT.commandLab.lessons;

const routeByIdMap = new Map(ROUTES.map((route) => [route.id, route] as const));

export function routeById(id: string): AppRoute {
  const route = routeByIdMap.get(id);
  if (!route) {
    throw new Error(`Unknown route id: ${id}`);
  }
  return route;
}

export const ROUTE_META: Record<string, RouteMeta> = Object.fromEntries(
  ROUTES.map((route) => [route.path, { title: route.title, sub: route.subtitle }])
);

export const NAV_GROUPS: NavGroup[] = APP_CONTENT.navGroups.map((group) => ({
  title: group.title,
  items: group.routeIds.map((routeId) => {
    const route = routeById(routeId);
    return { route: route.path, label: route.label, icon: route.icon };
  }),
}));

export const MOBILE_NAV: NavItem[] = APP_CONTENT.mobileNavRouteIds.map((routeId) => {
  const route = routeById(routeId);
  return { route: route.path, label: route.mobileLabel, icon: route.icon };
});

export const MORE_NAV: NavItem[] = APP_CONTENT.moreRouteIds.map((routeId) => {
  const route = routeById(routeId);
  return { route: route.path, label: route.label, icon: route.icon };
});

export const FEATURES: FeatureCard[] = APP_CONTENT.dashboard.features.map((feature) => ({
  icon: feature.icon,
  iconBg: ACCENT_COLORS[feature.iconBgToken] ?? feature.iconBgToken,
  title: feature.title,
  body: feature.body,
  route: routeById(feature.routeId).path,
}));

export const LEARN_CARDS: ConceptCardContent[] = APP_CONTENT.learnCards.map((card) => ({
  emoji: card.emoji,
  title: card.title,
  meta: card.meta,
  body: card.body,
  accent: ACCENT_COLORS[card.accentToken] ?? card.accentToken,
}));

export const INTERNALS_CARDS: ConceptCardContent[] = APP_CONTENT.internalsCards.map((card) => ({
  emoji: card.emoji,
  title: card.title,
  meta: card.meta,
  body: card.body,
  accent: ACCENT_COLORS[card.accentToken] ?? card.accentToken,
}));
